# 感情分析の疑似シミュレーション
# （実際のDLモデルを簡略化したもの）

# 感情辞書（実際のDLは自動でこれを学習する）
positive_words = {
    "良い": 1.0, "最高": 1.5, "素晴らしい": 1.5, "好き": 0.8,
    "おすすめ": 1.0, "満足": 1.0, "便利": 0.9, "嬉しい": 1.0
}
negative_words = {
    "悪い": -1.0, "最悪": -1.5, "ダメ": -1.2, "嫌い": -1.0,
    "失望": -1.3, "不満": -1.0, "使えない": -1.2, "返品": -0.8
}
negation_words = ["ない", "なかった", "全然", "まったく"]  # 否定語

# テストするレビューを変えてください ↓
reviews = [
    "この商品は素晴らしい。満足しています。",
    "最悪でした。全然使えない。返品します。",
    "悪くはないですが、もう少し改善してほしい。",
    "思ったより良くなかった。",  # 否定+ポジティブ語の組み合わせ
]

def analyze_sentiment(text):
    score = 0
    words = list(text)

    for word, val in positive_words.items():
        if word in text:
            # 否定語が直前にあるか確認
            pos = text.find(word)
            context = text[max(0, pos-5):pos]
            if any(neg in context for neg in negation_words):
                score -= val  # 否定で反転
            else:
                score += val

    for word, val in negative_words.items():
        if word in text:
            score += val

    if score > 0.5:
        return "ポジティブ", score
    elif score < -0.5:
        return "ネガティブ", score
    else:
        return "ニュートラル", score

for review in reviews:
    sentiment, score = analyze_sentiment(review)
    print(f"レビュー: {review}")
    print(f"  → 感情: {sentiment}（スコア: {score:.2f}）")
    print()

